#include <iostream>
#include <utility>
#include <type_traits>

struct Safe {
    Safe() = default;
    Safe(Safe&&) noexcept = default;
    Safe(const Safe&) = default;
};

struct Risky {
    Risky() = default;
    Risky(Risky&&) {} // not noexcept
    Risky(const Risky&) = default;
};

template <typename T>
bool will_move() {
    T obj{};
    // move_if_noexcept returns T&& when noexcept-movable, const T& otherwise
    return std::is_rvalue_reference_v<decltype(std::move_if_noexcept(obj))>;
}

int main() {
    int sel;
    std::cin >> sel;
    if (sel == 1) {
        std::cout << "Safe: " << (will_move<Safe>() ? "move" : "copy") << "\n";
    } else {
        std::cout << "Risky: " << (will_move<Risky>() ? "move" : "copy") << "\n";
    }
    return 0;
}

