#include <iostream>
#include <utility>
#include <vector>

void transfer_first(std::vector<int>& src, int& dest) {
    dest = std::move_if_noexcept(src[0]);
}

int main() {
    int n;
    std::cin >> n;
    std::vector<int> v(n);
    for (int i = 0; i < n; ++i)
        std::cin >> v[i];

    int dest = 0;
    transfer_first(v, dest);

    std::cout << "transferred: " << dest << "\n";
    std::cout << "remaining:";
    for (int i = 1; i < n; ++i)
        std::cout << " " << v[i];
    std::cout << "\n";
    return 0;
}
